noncompliant:
void* ptr = malloc(sizeof(int));
int address = (int)ptr; // Noncompliant: casting pointer to int

char* str = "hello";
long addr = reinterpret_cast<long>(str); // Noncompliant: casting pointer to integral type

int* int_ptr = new int(42);
uintptr_t value = (uintptr_t)int_ptr; // Noncompliant: should use proper conversion

compliant:
#include <cstdint>

void* ptr = malloc(sizeof(int));
uintptr_t address = reinterpret_cast<uintptr_t>(ptr); // Compliant: use uintptr_t for pointer arithmetic

// If you need to work with addresses
char* str = "hello";
std::uintptr_t addr = reinterpret_cast<std::uintptr_t>(str);

// Better: avoid pointer-to-int conversion altogether
int* int_ptr = new int(42);
int value = *int_ptr; // Compliant: dereference instead of converting address
